#include <bits/stdc++.h>
using namespace std;
string s,t;
int cot,pos;
int main(){
	getline(cin,s);
	getline(cin,t);
	s=' '+s+' ';
	t=' '+t+' ';
	for(int i=0;i<s.size();i++){
		s[i]=tolower(s[i]);
	}
	for(int i=0;i<t.size();i++){
		t[i]=tolower(t[i]);
	}
	if(t.find(s)==-1){
		cout<<"-1";
	}else{
		int n=0;
		while(t.find(s,n)!=-1){
			cot++;
			n=t.find(s,n)+1;
		}
		cout<<cot<<" "<<t.find(s);
	}
	return 0;
}
